#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(b,c) for(int c=head[b];c;c=nxt[c])
typedef long long LL;
inline int read()
{
	int res(0);char ch(getchar());while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline void chkmax(T&x,const T&w){x<w?x=w:T();}
template<typename T> inline void chkmin(T&x,const T&w){w<x?x=w:T();}
const int N=1e5+10,INF=0x3f3f3f3f;int head[N],des[N<<1],nxt[N<<1],cgt,n,a[N],siz[N];
LL buf[N*114],*ToFa[N],*ToMe[N],*tmp=buf;
inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
inline void add(LL *t,int p,const int &w){while(p<=t[0])t[p]+=w,p+=(p&-p);}
inline LL qry(LL *t,int p){LL res(0);if(p>t[0])p=t[0];while(p)res+=t[p],p^=(p&-p);return res;}

namespace TreeCut
{
	int top[N],fa[N],dep[N],mxs[N],cnt;
	inline void dfs1(const int &u=1,const int &f=0)
	{
		dep[u]=dep[fa[u]=f]+1;siz[u]=1;int mx=0;
		grep(u,i)if(des[i]!=f){int v=des[i];dfs1(v,u);siz[u]+=siz[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;}
	}
	inline void dfs2(const int &u=1,const int &fa=0,const int &tp=1)
	{
		top[u]=tp;if(mxs[u])dfs2(mxs[u],u,tp);
		grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs2(des[i],u,des[i]);
	}
	inline int Dis(int x,int y)
	{
		int ans=dep[x]+dep[y];
		while(top[x]!=top[y])dep[top[x]]<dep[top[y]]?y=fa[top[y]]:x=fa[top[x]];
		return ans-2*dep[dep[x]<dep[y]?x:y];
	}
}

namespace Build
{
	using TreeCut::Dis;int fa[N],mxd[N],Rt,Mn,Sz;bool vis[N];
	inline void getRt(const int &u,const int &fa=0)
	{
		siz[u]=1;int mx=0;
		grep(u,i)if(!vis[des[i]]&&des[i]!=fa)
		{
			int v=des[i];getRt(v,u);
			siz[u]+=siz[v];chkmax(mx,siz[v]);
		}
		chkmax(mx,Sz-siz[u]);mx<Mn?Mn=mx,Rt=u:0; 
	}
	int RT;inline void getDis(const int &u,const int &fa=0,const int &dep=1)
	{
		grep(u,i)if(!vis[des[i]]&&des[i]!=fa)getDis(des[i],u,dep+1);
		chkmax(mxd[RT],dep);
	}
	inline void dfs(const int &u,const int &f=0,const int &dep=1)
	{
		add(ToMe[RT],dep,a[u]);add(ToFa[RT],Dis(u,fa[RT])+1,a[u]);
		grep(u,i)if(!vis[des[i]]&&des[i]!=f)dfs(des[i],u,dep+1);
	}
	inline void Solve(int u)
	{
		vis[u]=true; getDis(RT=u); ToMe[u]=tmp; ToMe[u][0]=mxd[u];tmp+=mxd[u]+2;
		ToFa[u]=tmp; tmp[0]=mxd[fa[u]]; tmp+=mxd[fa[u]]+2; dfs(u); 
		grep(u,i)if(!vis[des[i]]){int v=des[i];Mn=INF;Sz=siz[v];getRt(v);fa[Rt]=u;Solve(Rt);}
	}
	inline void build(){Sz=n;Mn=INF;getRt(1);Solve(Rt);}
}

namespace Solve
{
	using TreeCut::Dis;using Build::fa;
	inline void Add(const int &x,const int &v)
	{
		int p=x;while(p)
		{
			
			add(ToMe[p],Dis(x,p)+1,v);if(!fa[p])break;
			add(ToFa[p],Dis(x,fa[p])+1,v);p=fa[p];
		}
	}
	inline LL Qry(const int &x,const int &d)
	{
		LL ans=0;int p=x,D=0;while(p)
		{
			if(d>=D)ans+=qry(ToMe[p],d-D+1);if(!fa[p])break;
			D=Dis(x,fa[p]);if(d>=D)ans-=qry(ToFa[p],d-D+1);p=fa[p];			
		}
		return ans;
	}
}

int main()
{
//	FIN("data.in");FOUT("mine.out");
	n=read();int Q=read();
	rep(1,n,i)a[i]=read();rep(2,n,i)ins(read(),read());
	TreeCut::dfs1();TreeCut::dfs2();Build::build();
	LL lst=0;while(Q--)
	{
		if(read()) {int x=read()^lst,v=read()^lst;Solve::Add(x,v-a[x]);a[x]=v;}
		else {int x=read()^lst,d=read()^lst;printf("%lld\n",lst=Solve::Qry(x,d));}
	}
}
